  try {
    const userId = req.user.id;
    const page = Math.max(1, parseInt(req.query.page) || 1);
    const limit = Math.min(50, parseInt(req.query.limit) || 20);
    const offset = (page - 1) * limit;

    // Get friend IDs
    const friendships = await safeQuery(`SELECT CASE WHEN user_id = ? THEN friend_id ELSE user_id END AS fid
       FROM friendships WHERE (user_id = ? OR friend_id = ?) AND status = 'accepted'`, [userId, userId, userId]);
