       WHERE p.author_id IN (${placeholders})
         AND p.is_approved = 1
       ORDER BY p.created_at DESC
       LIMIT ? OFFSET ?`, [userId, ...allIds, limit, offset]);
    res.json({
      success: true,
      data: posts,
      pagination: {
        page,
        limit,
        count: posts.length
      }
    });
  } catch (err) {
    console.error('Feed error:', err);
    res.status(500).json({
      success: false,
      message: 'Could not load feed',
      error: err.message
    });
  }
});

