    const page = Math.max(1, parseInt(req.query.page) || 1);
    const limit = Math.min(50, parseInt(req.query.limit) || 20);
    const offset = (page - 1) * limit;

    // Get friend IDs
    const friendships = await safeQuery(
      `SELECT CASE WHEN user_id = ? THEN friend_id ELSE user_id END AS fid
       FROM friendships WHERE (user_id = ? OR friend_id = ?) AND status = 'accepted'`,
      [userId, userId, userId]
    );
    const friendIds = friendships.map(r => r.fid);
    const allIds = [userId, ...friendIds];
    const placeholders = allIds.map(() => '?').join(',');

    const posts = await safeQuery(
      `SELECT p.id, p.uuid, p.author_id, p.content, p.image_url,
              p.visibility, p.is_approved, p.kindness_pts, p.created_at,
              u.username, u.display_name, u.avatar_url,
              (SELECT COUNT(*) FROM post_likes pl WHERE pl.post_id = p.id) AS like_count,
